import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Download, Trash2, FileAudio, Calendar, HardDrive, AlertCircle } from 'lucide-react';

const Gravacoes = () => {
  const [gravacoes, setGravacoes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadGravacoes();
  }, []);

  const loadGravacoes = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem('adminToken');
      const res = await axios.get('/api/admin/chat/gravacoes', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setGravacoes(res.data);
    } catch (err) {
      setError(err.response?.data?.detail || 'Erro ao carregar gravações');
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = async (arquivo) => {
    try {
      const token = localStorage.getItem('adminToken');
      window.open(`/api/admin/chat/gravacao/${arquivo}?token=${token}`, '_blank');
    } catch (err) {
      alert('Erro ao baixar gravação');
    }
  };

  const handleDelete = async (arquivo) => {
    if (!window.confirm('Tem certeza que deseja excluir esta gravação?')) return;

    try {
      const token = localStorage.getItem('adminToken');
      await axios.delete(`/api/admin/chat/gravacao/${arquivo}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setGravacoes(gravacoes.filter(g => g.arquivo !== arquivo));
    } catch (err) {
      alert('Erro ao excluir gravação');
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i];
  };

  const formatDate = (isoString) => {
    if (!isoString) return '-';
    try {
      return new Date(isoString).toLocaleString('pt-BR');
    } catch {
      return '-';
    }
  };

  const isExpiringSoon = (expiraEm) => {
    if (!expiraEm) return false;
    try {
      const expira = new Date(expiraEm);
      const agora = new Date();
      const diff = expira - agora;
      const dias = diff / (1000 * 60 * 60 * 24);
      return dias <= 1 && dias > 0;
    } catch {
      return false;
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600"></div>
      </div>
    );
  }

  return (
    <div className="p-6">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-800 mb-2">Gravações</h1>
        <p className="text-gray-600">Gerencie todas as gravações de atendimento. Gravações são excluídas automaticamente após 5 dias.</p>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-4">
          {error}
        </div>
      )}

      <div className="bg-white rounded-lg shadow">
        {gravacoes.length === 0 ? (
          <div className="text-center py-12">
            <FileAudio className="w-16 h-16 text-gray-300 mx-auto mb-4" />
            <p className="text-gray-500">Nenhuma gravação encontrada</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Protocolo
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Arquivo
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Data Criação
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Expira Em
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Tamanho
                  </th>
                  <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Ações
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {gravacoes.map((gravacao) => (
                  <tr key={gravacao.arquivo} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <FileAudio className="w-5 h-5 text-purple-600 mr-2" />
                        <span className="text-sm font-medium text-gray-900">{gravacao.protocolo}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className="text-sm text-gray-600">{gravacao.arquivo}</span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center text-sm text-gray-600">
                        <Calendar className="w-4 h-4 mr-1" />
                        {formatDate(gravacao.data_criacao)}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        {isExpiringSoon(gravacao.expira_em) && (
                          <AlertCircle className="w-4 h-4 text-yellow-500 mr-1" />
                        )}
                        <span className={`text-sm ${isExpiringSoon(gravacao.expira_em) ? 'text-yellow-600 font-semibold' : 'text-gray-600'}`}>
                          {formatDate(gravacao.expira_em)}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center text-sm text-gray-600">
                        <HardDrive className="w-4 h-4 mr-1" />
                        {formatBytes(gravacao.tamanho)}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <button
                        onClick={() => handleDownload(gravacao.arquivo)}
                        className="text-blue-600 hover:text-blue-900 mr-3 inline-flex items-center"
                        title="Baixar"
                      >
                        <Download className="w-4 h-4 mr-1" />
                        Baixar
                      </button>
                      <button
                        onClick={() => handleDelete(gravacao.arquivo)}
                        className="text-red-600 hover:text-red-900 inline-flex items-center"
                        title="Excluir"
                      >
                        <Trash2 className="w-4 h-4 mr-1" />
                        Excluir
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <div className="mt-4 bg-yellow-50 border border-yellow-200 rounded-lg p-4">
        <div className="flex items-start">
          <AlertCircle className="w-5 h-5 text-yellow-600 mr-2 mt-0.5" />
          <div className="text-sm text-yellow-800">
            <p className="font-semibold mb-1">Atenção:</p>
            <p>Gravações são automaticamente excluídas após 5 dias da data de criação. Faça o download das gravações importantes antes do prazo de expiração.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Gravacoes;
